import {
  GIT_COMMIT_FIRST_LINE_LIMIT,
  PROJECT_CLI,
  PROJECT_NAME,
  PROJECT_NAME_DISPLAY,
} from "#src/constants.js";

// These are template strings for generated hook scripts.
// They are written to disk as standalone Node.js scripts, not executed in this process.
// The use of execSync in templates is intentional for git hook runners.

export const RUNNER_TEMPLATE = `#!/bin/sh
# ${PROJECT_NAME_DISPLAY} pre-commit hook runner — Auto-generated by ${PROJECT_CLI} init
node --input-type=module << 'HOOK_SCRIPT'
import { execFileSync } from 'child_process';

const hooks = {{HOOKS_JSON}};

function getStagedFiles(filter) {
  try {
    const output = execFileSync('git', ['diff', '--cached', '--name-only', '--diff-filter=ACMR'], { encoding: 'utf-8' });
    const files = output.trim().split('\\n').filter(Boolean);
    if (!filter) return files;
    const re = new RegExp(filter.replace(/\\*\\*/g, '.*').replace(/\\*/g, '[^/]*'));
    return files.filter(f => re.test(f));
  } catch { return []; }
}

let exitCode = 0;
let lastLang = '';
for (const hook of hooks) {
  const files = getStagedFiles(hook.stagedFilter);
  if (files.length === 0) continue;
  const hookLang = hook.language ?? '';
  if (hookLang !== lastLang) {
    console.log(hookLang ? \`\\n[\${hookLang}]\` : \`\\n[global]\`);
    lastLang = hookLang;
  }
  console.log(\`  Running \${hook.name}...\`);
  const [bin, ...baseArgs] = hook.command.split(/\\s+/);
  const args = hook.passFiles === false ? baseArgs : [...baseArgs, ...files];
  try {
    execFileSync(bin, args, { stdio: 'inherit' });
    if (hook.modifiesFiles) {
      execFileSync('git', ['add', ...files], { stdio: 'inherit' });
    }
  } catch (e) {
    console.error(\`\${hook.name} failed\`);
    exitCode = 1;
  }
}
process.exit(exitCode);
HOOK_SCRIPT
`;

export const SECRET_SCAN_TEMPLATE = `#!/usr/bin/env node
// ${PROJECT_NAME_DISPLAY} secret scanner
import fs from 'fs';

const PATTERNS = [
  /(?:api[_-]?key|apikey)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /(?:secret|password|passwd|pwd)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /(?:token|bearer)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /-----BEGIN (?:RSA |EC |DSA )?PRIVATE KEY-----/,
  /ghp_[a-zA-Z0-9]{36}/,
  /gho_[a-zA-Z0-9]{36}/,
  /github_pat_[a-zA-Z0-9]{22}_[a-zA-Z0-9]{59}/,
  /sk-[a-zA-Z0-9]{32,}/,
  /xox[bpors]-[a-zA-Z0-9-]{10,}/,
  /AKIA[0-9A-Z]{16}/,
];

// Lines matching any of these are safe (env var refs, placeholders, examples)
const FALSE_POS = [
  /['"](?:your-|example-|test-|dummy-|fake-|placeholder)/i,
  /\\\\*\\$\\{/,
  /process\\.env/,
  /os\\.environ/,
  /import\\.meta\\.env/,
  /\\bgetenv\\b/,
  /['"](?:changeme|replace.?me|xxx+|\\*{3,}|TODO|FIXME)/i,
  /sk-[a-z]{3,6}\\d{2,4}(?:\\.\\.\\.|\\*)/,
];

const EXCLUDED = [
  /tests?\\//,
  /\\.test\\.[jt]sx?$/,
  /\\.spec\\.[jt]sx?$/,
  /__tests__\\//,
  /\\/references\\//,
  /\\/templates\\//,
  /docs\\//,
  /\\.md$/,
];

/**
 * Shannon entropy: real secrets have high entropy (>3.5),
 * env var names and placeholders have low entropy.
 */
function entropy(s) {
  if (s.length === 0) return 0;
  const freq = {};
  for (const c of s) freq[c] = (freq[c] || 0) + 1;
  let e = 0;
  for (const k in freq) {
    const p = freq[k] / s.length;
    e -= p * Math.log2(p);
  }
  return e;
}

/** Extract the quoted value from a matched line */
function extractQuotedValue(line) {
  const m = line.match(/[:=]\\s*['"]([^'"]{8,})['"]/);
  return m ? m[1] : null;
}

const files = process.argv.slice(2).filter(f => !EXCLUDED.some(p => p.test(f)));
const findings = [];
for (const file of files) {
  try {
    const content = fs.readFileSync(file, 'utf-8');
    const lines = content.split('\\n');
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const matchedPattern = PATTERNS.find(p => p.test(line));
      if (!matchedPattern) continue;
      if (FALSE_POS.some(fp => fp.test(line))) continue;

      // For key=value patterns, check entropy of the value
      const val = extractQuotedValue(line);
      if (val && entropy(val) < 3.0) continue;

      findings.push({ file, line: i + 1, text: line.trim().substring(0, 80) });
    }
  } catch {}
}
if (findings.length > 0) {
  for (const f of findings) {
    console.error(\`[secret-scan] \${f.file}:\${f.line}  \${f.text}\`);
  }
  console.error(\`\\n\${findings.length} potential secret(s) found. If these are false positives, move them to a file excluded by the scanner (tests/, templates/, references/, docs/).\`);
  process.exit(1);
}
`;

